var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"네? 제가…… <color=#ffd34c>반드시 멸해야만 하는 악</color>?","JPN":"え？　私が……<color=#ffd34c>滅ぼすべき悪</color>？","ENG":"Me? <color=#ffd34c>The evil that must be destroyed</color>?","TWN":"什麼？我就是……<color=#ffd34c>該死的惡人</color>？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니, 그보다 숙부님이 돌아가셨다고요? 정말로요?","JPN":"いえ、それよりも叔父様がお亡くなりに？　本当ですか？","ENG":"Wait, did you just say Uncle is dead? Is that true?","TWN":"等等，你說叔叔死了？是真的嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그래! 사회 혼란을 우려해 홍보팀이 보도를 막고 있지만, 명명백백한 사실이야!","JPN":"そうだ！　広報チームが社会的混乱を危惧して報道を止めてるけど、\\n明々白々たる事実だ！","ENG":"Correct! The PR team is preventing the report from being released for fear of causing social uproar, but it is an undeniable fact!","TWN":"沒錯！公關部的人怕引起社會混亂，所以把報導擋下來，但這件事是千真萬確的！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"그리고 감찰과는 이미 네가 끔찍한 범죄를 저질렀다는 증거와 증언까지 모두 확보했어!","JPN":"それに監察課は、お前の残酷な犯行を裏付ける証拠と証言をすべて確保してるから！","ENG":"Plus, Investigations has already collected indisputable evidence of your heinous crime!","TWN":"而監察科已經掌握你的犯罪證據和供詞！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"내 안의 <color=#ffd34c>파사의 목소리</color>도……. 네가 범인이라고 속삭이고 있다!","JPN":"私の中の<color=#ffd34c>破邪の声</color>も……お前が犯人だと囁いている！","ENG":"Even the <color=#ffd34c>Voice of Evil Eradication</color> within me... He whispers that you’re the culprit!","TWN":"我裡面的<color=#ffd34c>破邪之聲</color>……也說你是就是犯人！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"짜잔.","JPN":"ババン。","ENG":"Kachow!","TWN":"鏘鏘。"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"……파사의 목소리라고? 그건 뭐지?","JPN":"……破邪の声だって？　それはなんだ？","ENG":"The Voice of Evil Eradication? What’s that?","TWN":"……破邪之聲？那是什麼東東？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"뭐야? 너도 모르는 설정이야?","JPN":"えっ？　自分でもわからない設定なわけ？","ENG":"Huh? You don’t know the set-up either?","TWN":"你也不知道喔？這些台詞不是你們一起寫的嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"CHOI_ALPHA_NULL_SHORT","text":{"KOREA":"설정이라니! 그 무슨 망발이냐!","JPN":"設定だなんて！　失敬ではないか！","ENG":"Set-up?! What are you talking about?!","TWN":"什麼台詞！胡說八道什麼！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"더 이상의 저항은 소용없다! 신지아 대표와 그 졸개들!","JPN":"これ以上抵抗しても無駄だよ！　ヒメノ代表とその手下ども！","ENG":"Shin Jia and her henchmen! There’s no use in resisting!","TWN":"無須再抵抗！沈佳代表和你們這群小跟班！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"CHOI_ALPHA_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"순순히 항복하지 않는다면 힘으로라도 데려가겠어!","JPN":"大人しく降伏しないなら、力づくで連れてくよ！","ENG":"Surrender now, or I will take you in by force!","TWN":"乖乖地投降吧！否則別怪我不客氣！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"JIA_ALPHA_NULL_NULL","text":{"KOREA":"아니요. 저는…….","JPN":"いえ、私は……","ENG":"No, I…","TWN":"等一下，我……"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"자, 잠깐! 리더는 어젯밤에 우리랑 같이 전철을 타고 돌아왔다고!","JPN":"ちょ、ちょっと待って！　リーダーは昨夜、私たちと一緒に電車で帰ってきたの！","ENG":"H-hold it! Leader took the subway with us back home last night!","TWN":"先等等！老大昨天晚上是和我們一起搭地鐵回來的！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEAROM_ALPHA_NULL_NULL","text":{"KOREA":"처음 타 본다고 찍은 기념사진도 있단 말이야!","JPN":"初めて電車に乗るってことで、記念写真まで撮ったんだから！","ENG":"We even took a selfie to commemorate her first ride!","TWN":"老大說她是第一次搭地鐵，所以我們還有拍照留念呢！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":{"char_id":"SEAROM_ALPHA_NULL_NULL","face":"UNIT_SERIOUS"},"C":{"char_id":"JIA_ALPHA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"진짜?","JPN":"本当に？","ENG":"Is this true?","TWN":"真的嗎？"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SURPRISE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"아, 아니지. 사진 같은 건 조작할 수 있다고 했어. 하마터면 속을 뻔했네.","JPN":"い、いや。写真は偽造もできるって言ってた。危うく騙されるとこだった。","ENG":"On second thought, no. Anyone can fake a photo. You almost got me there.","TWN":"不…不對！照片這種東西是可以偽造的吧？！差點上當！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_HATE"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SPEAR_ALPHA_NULL_SHORT","text":{"KOREA":"잘 들어, 버섯 머리. 이 범죄는 최소 한 명 이상의 공범이 가담한 정황이 있어.","JPN":"よーく聞いて、マッシュルーム。この犯罪は、最低でも一人以上の共犯者がいるとわかる状況証拠がある。","ENG":"Listen carefully, mushroom head. We already have information that at least one co-conspirator is involved.","TWN":"你給我聽好了，香菇頭！這次的犯罪事件，我們推測有超過一個以上的共犯！"},"stage":{"bg":"OFFICE_MESSED","slots":{"L":null,"C":{"char_id":"SPEAR_ALPHA_NULL_SHORT","face":"UNIT_SERIOUS"},"R":{"char_id":"GUARD_EXTRA_NANA_A","face":"UNIT_IDLE"}}}}]`);export{e as default};